// Remove Pinata API keys, keep only JWT
export const IPFS_CONFIG = {
  gateway: 'https://gateway.pinata.cloud/ipfs/',
  pinataJWT: process.env.REACT_APP_PINATA_JWT, // Only JWT needed
  maxFileSize: 52428800, // 50MB
  supportedFormats: [
    'image/jpeg', 'image/png', 'image/gif', 'image/svg+xml',
    'video/mp4', 'video/quicktime', 
    'audio/mpeg', 'audio/wav',
    'application/json'
  ]
};

// Contract addresses - Temporarily hardcoded to avoid env issues
export const CONTRACT_ADDRESSES = {
  marketplace: "0x2e74cffD2aCF6C7a8dBC866739301206bA8b7779",
  erc721: "0xBC32e90e6F64c945eA37C8f193d7277205031cC",
  erc1155: "0xFB7163481F8bF32272E9dc2548FE700C1d2108D2"
};

console.log('Using hardcoded CONTRACT_ADDRESSES:', CONTRACT_ADDRESSES);

// Network configurations
export const NETWORK_CONFIG = {
  sepolia: {
    chainId: '0xaa36a7',
    rpcUrl: process.env.REACT_APP_SEPOLIA_RPC_URL || 'https://sepolia.infura.io/v3/dce45d379ddc4a6bafd653d5293575cd',
    name: 'Sepolia Testnet',
    currency: 'ETH',
    explorerUrl: 'https://sepolia.etherscan.io'
  },
  localhost: {
    chainId: '0x7a69',
    rpcUrl: 'http://127.0.0.1:8545',
    name: 'Localhost',
    currency: 'ETH',
    explorerUrl: 'http://localhost:8545'
  }
};

// Contract ABIs
export const MARKETPLACE_ABI = [
  "function createListing(address tokenAddress, uint256 tokenId, uint256 price, uint256 amount, bool isERC1155) external",
  "function buyListing(uint256 listingId) external payable",
  "function cancelListing(uint256 listingId) external",
  "function listings(uint256 listingId) view returns (address seller, address tokenAddress, uint256 tokenId, uint256 price, uint256 amount, bool active, bool isERC1155)",
  "function listingCounter() view returns (uint256)",
  "event ListingCreated(uint256 indexed listingId, address indexed seller, address tokenAddress, uint256 tokenId, uint256 price, uint256 amount, bool isERC1155)",
  "event ListingSold(uint256 indexed listingId, address indexed buyer, uint256 price)",
  "event ListingCancelled(uint256 indexed listingId, address indexed seller)"
];

export const ERC721_ABI = [
  "function safeMint(address to, string memory uri, address royaltyRecipient, uint96 royaltyFraction) external returns (uint256)",
  "function ownerOf(uint256 tokenId) view returns (address)",
  "function tokenURI(uint256 tokenId) view returns (string)",
  "function approve(address to, uint256 tokenId) external",
  "function balanceOf(address owner) view returns (uint256)",
  "function name() view returns (string)",
  "function symbol() view returns (string)",
  "event Transfer(address indexed from, address indexed to, uint256 indexed tokenId)"
];

export const ERC1155_ABI = [
  "function mint(address account, uint256 amount, string memory tokenURI, address royaltyRecipient, uint96 royaltyFraction, bytes memory data) external",
  "function balanceOf(address account, uint256 id) view returns (uint256)",
  "function uri(uint256 id) view returns (string)",
  "function setApprovalForAll(address operator, bool approved) external",
  "function name() view returns (string)",
  "function symbol() view returns (string)",
  "event TransferSingle(address indexed operator, address indexed from, address indexed to, uint256 id, uint256 value)"
];

// Default network
export const DEFAULT_NETWORK = process.env.REACT_APP_DEFAULT_NETWORK || 'sepolia';
